// 1. Import required units for database, REST, and list operations
uses core.rest as rest;    // For constructing the JSON response
uses core.data as data;    // For executing SQL queries
uses core.list as list;    // For managing the response lists
uses core.string as str;   // For string conversions

// 2. Define the exported function (must match your Operation ID)
export function executeSql(requestBody: SqlQueryRequest): rest_response
begin
    // Use the fixed string check logic
    var sqlLower := str.toLowerCase(requestBody.sql);

    if (str.contains(sqlLower, 'delete') or str.contains(sqlLower, 'update')) then
        return rest.emptyResponse(403);

    var ds := data.findDataspace(requestBody.dataspace);
    var dt := data.findDataset(ds, requestBody.dataset);

    // 4. Build and execute the query
    var q := data.createQuery(requestBody.sql);
    data.addDataset(q, 'm', dt);
    var queryResult := data.executeQuery(q);

    // 5. Build the strictly typed response
    var responseRows := list.of<Row>();

    for tuple in queryResult do
    begin
        var row := instanceOf<Row>();
        var rowCols := list.of<Column>();

        // Iterate through dynamic column names returned by the query
        for colName in requestBody.expected_columns do
        begin
            var col := instanceOf<Column>();
            col.name := colName;
            // Convert all values to string for the standardized envelope
            col.value := data.field<string>(tuple, colName); 
            list.add(rowCols, col);
        end;

        row.columns  := rowCols;
        list.add(responseRows, row);
    end;

    // 6. Wrap in the final response object
    var finalResult := instanceOf<QueryResponse>();
    finalResult.rows := responseRows;

    return rest.responseOf(200, finalResult); //
end
